// GMAIL_Send_Confirmation v1.0.0
// Validate input and prepare email data
const raw = $input.first()?.json || {};

// Webhook body comes through raw.body or directly at root
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'GMAIL_Send_Confirmation', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
  }}];
}

// Extract email from multiple possible paths
const userEmail = input.user_email || input.final_email || input.email;

// Validate required fields
if (!userEmail) {
  return ve('MISSING_FIELD', 'user_email, final_email, or email is required');
}

// Basic email format validation
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!EMAIL_RE.test(String(userEmail))) {
  return ve('INVALID_TYPE', 'Invalid email format');
}

const userName = input.user_name || input.customer_name || 'Cliente';
const startTime = input.start_time || input.appointment_time || 'Por confirmar';
const serviceName = input.service_name || input.appointment_type || 'Consulta';

return [{ json: {
  success: true,
  user_email: userEmail,
  user_name: userName,
  start_time: startTime,
  service_name: serviceName,
  _validated: true
}}];

// Gate: only pass valid items to Gmail
const input = $input.first().json;
if (!input._validated) return [];
return [{ json: input }];

// Gate: pass validation errors to Format Output
const input = $input.first().json;
if (input._validated) return [];
return [{ json: input }];

