// Handle Gmail error
const e = $input.first().json;
let error_code = 'GMAIL_ERROR';
let error_message = e.message || e.error?.message || 'Gmail send failed';

if (error_message.includes('insufficient_permission') || error_message.includes('401')) {
  error_code = 'GMAIL_AUTH_ERROR';
  error_message = 'Gmail authentication failed - please re-authenticate';
} else if (error_message.includes('quota') || error_message.includes('429')) {
  error_code = 'GMAIL_RATE_LIMIT';
  error_message = 'Gmail rate limit exceeded';
}

return [{ json: {
  success: false,
  error_code,
  error_message,
  data: null,
  _meta: { source: 'GMAIL_Send_Confirmation', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Format Gmail success response
const gmailResponse = $input.first()?.json || {};

return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: {
    message_id: gmailResponse.id || null,
    thread_id: gmailResponse.threadId || null,
    sent_to: $('Validate Input').first().json.user_email
  },
  _meta: {
    source: 'GMAIL_Send_Confirmation',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];

// UNIFIED OUTPUT — Standard Contract (§3.2)
const items = $input.all();
let finalItem = items.find(i => i.json.data !== undefined || i.json.error_code !== undefined);
if (!finalItem) finalItem = items.find(i => i.json._validated === false);
if (!finalItem) { 
  return [{ json: { success: false, error_code: 'PIPELINE_ERROR', error_message: 'No valid output found', data: null, _meta: { source: 'GMAIL_Send_Confirmation', timestamp: new Date().toISOString(), workflow_id: $workflow.id } } }]; 
}
const input = finalItem.json;
return [{ json: {
  success: input.success === true,
  error_code: input.error_code || null,
  error_message: input.error_message || null,
  data: input.data || null,
  _meta: input._meta || {
    source: 'GMAIL_Send_Confirmation',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];
